/// Bind group 2: `MaterialUniform` at binding 0, then each texture + sampler pair.
fn push_material_bind_group_layout_entries(entries: &mut Vec<wgpu::BindGroupLayoutEntry>) {
    entries.push(wgpu::BindGroupLayoutEntry {
        binding: 0,
        visibility: wgpu::ShaderStages::VERTEX_FRAGMENT,
        ty: wgpu::BindingType::Buffer {
            ty: wgpu::BufferBindingType::Uniform,
            has_dynamic_offset: false,
            min_binding_size: None,
        },
        count: None,
    });
    entries.push(wgpu::BindGroupLayoutEntry {
        binding: 1,
        visibility: wgpu::ShaderStages::FRAGMENT,
        ty: wgpu::BindingType::Texture {
            sample_type: wgpu::TextureSampleType::Float { filterable: true },
            view_dimension: wgpu::TextureViewDimension::D2,
            multisampled: false,
        },
        count: None,
    });
    entries.push(wgpu::BindGroupLayoutEntry {
        binding: 2,
        visibility: wgpu::ShaderStages::FRAGMENT,
        ty: wgpu::BindingType::Sampler(wgpu::SamplerBindingType::Filtering),
        count: None,
    });
    entries.push(wgpu::BindGroupLayoutEntry {
        binding: 3,
        visibility: wgpu::ShaderStages::FRAGMENT,
        ty: wgpu::BindingType::Texture {
            sample_type: wgpu::TextureSampleType::Float { filterable: true },
            view_dimension: wgpu::TextureViewDimension::D2,
            multisampled: false,
        },
        count: None,
    });
    entries.push(wgpu::BindGroupLayoutEntry {
        binding: 4,
        visibility: wgpu::ShaderStages::FRAGMENT,
        ty: wgpu::BindingType::Sampler(wgpu::SamplerBindingType::Filtering),
        count: None,
    });
    entries.push(wgpu::BindGroupLayoutEntry {
        binding: 5,
        visibility: wgpu::ShaderStages::FRAGMENT,
        ty: wgpu::BindingType::Texture {
            sample_type: wgpu::TextureSampleType::Float { filterable: true },
            view_dimension: wgpu::TextureViewDimension::Cube,
            multisampled: false,
        },
        count: None,
    });
    entries.push(wgpu::BindGroupLayoutEntry {
        binding: 6,
        visibility: wgpu::ShaderStages::FRAGMENT,
        ty: wgpu::BindingType::Sampler(wgpu::SamplerBindingType::Filtering),
        count: None,
    });
}

/// Returns `(layout, scene_uniform_size_bytes)` for WGSL `@group(1)` clustered-forward scene data.
pub fn create_renderide_scene_bind_group_layout(device: &wgpu::Device, label: &str) -> (wgpu::BindGroupLayout, u64) {
    let mut entries = Vec::new();
    push_renderide_scene_bind_group_layout_entries(&mut entries);
    let scene_uniform_size = std::mem::size_of::<crate::gpu::pipeline::SceneUniforms>() as u64;
    let layout = device.create_bind_group_layout(&wgpu::BindGroupLayoutDescriptor {
        label: Some(label),
        entries: &entries,
    });
    (layout, scene_uniform_size)
}

pub fn create_material_bind_group_layout(device: &wgpu::Device, label: &str) -> wgpu::BindGroupLayout {
    let mut entries = Vec::new();
    push_material_bind_group_layout_entries(&mut entries);
    device.create_bind_group_layout(&wgpu::BindGroupLayoutDescriptor {
        label: Some(label),
        entries: &entries,
    })
}

/// `texture_views_and_samplers` must contain one `(view, sampler)` per texture property in Properties order.
pub fn create_material_bind_group(
    device: &wgpu::Device,
    layout: &wgpu::BindGroupLayout,
    label: &str,
    material_uniform_buffer: &wgpu::Buffer,
    texture_views_and_samplers: &[(&wgpu::TextureView, &wgpu::Sampler)],
) -> wgpu::BindGroup {
    let mut entries: Vec<wgpu::BindGroupEntry> = Vec::new();
    entries.push(wgpu::BindGroupEntry {
        binding: 0,
        resource: wgpu::BindingResource::Buffer(wgpu::BufferBinding {
            buffer: material_uniform_buffer,
            offset: 0,
            size: None,
        }),
    });
    let mut b: u32 = 1;
    for (view, sampler) in texture_views_and_samplers {
        entries.push(wgpu::BindGroupEntry {
            binding: b,
            resource: wgpu::BindingResource::TextureView(view),
        });
        b += 1;
        entries.push(wgpu::BindGroupEntry {
            binding: b,
            resource: wgpu::BindingResource::Sampler(sampler),
        });
        b += 1;
    }
    device.create_bind_group(&wgpu::BindGroupDescriptor { label: Some(label), layout, entries: &entries })
}

/// Primitive assembly for pass 0 (from ShaderLab `Cull`). Tags: ` IgnoreProjector` = `True`; `LightMode` = `ForwardBase`; `QUEUE` = `Transparent`; `RenderType` = `Opaque`.
pub fn primitive_state_pass0() -> wgpu::PrimitiveState {
    wgpu::PrimitiveState {
        topology: wgpu::PrimitiveTopology::TriangleList,
        strip_index_format: None,
        front_face: wgpu::FrontFace::Ccw,
        cull_mode: Some(wgpu::Face::Back),
        unclipped_depth: false,
        polygon_mode: wgpu::PolygonMode::Fill,
        conservative: false,
    }
}

/// Depth/stencil for pass 0 when a depth attachment is used.
pub fn depth_stencil_state_pass0(depth_format: wgpu::TextureFormat) -> wgpu::DepthStencilState {
    wgpu::DepthStencilState {
        format: depth_format,
        depth_write_enabled: true,
        depth_compare: wgpu::CompareFunction::LessEqual,
        stencil: wgpu::StencilState {
        front: wgpu::StencilFaceState::IGNORE,
        back: wgpu::StencilFaceState::IGNORE,
        read_mask: 0,
        write_mask: 0,
    },
        bias: wgpu::DepthBiasState {
            constant: 0,
            slope_scale: 0.0,
            clamp: 0.0,
        },
    }
}

/// First color target for pass 0 (blend + write mask from ShaderLab).
pub fn color_target_state_pass0(surface_format: wgpu::TextureFormat) -> Option<wgpu::ColorTargetState> {
    Some(wgpu::ColorTargetState {
                format: surface_format,
                blend: None,
                write_mask: wgpu::ColorWrites::ALL,
            })
}

